@patch
def delete(self:Run):
    "Delete run, or mark as tracked deletion if tracking is set"
    if _docx_tracking:
        el = _rev_el('del', _docx_tracking)
        for t in self._r.findall(qn('w:t')): t.tag = qn('w:delText')
        self._r.addprevious(el)
        el.append(self._r)
    else: self._r.getparent().remove(self._r)

