@patch
def delete(self:Paragraph):
    "Delete paragraph, or mark all runs as tracked deletions"
    if _docx_tracking:
        for r in self.runs:
            if (rev:=r.revision) and rev.typ=='del': continue
            r.delete()
    else: self._p.getparent().remove(self._p)

